254	// finalizeWarnings rebuilds the deprecated Warnings string slice from Issues
255	// and sorts Issues deterministically so downstream callers see stable output.
256	func (g *Graph) finalizeWarnings() {
257		sort.SliceStable(g.Issues, func(i, j int) bool {
258			if g.Issues[i].Kind != g.Issues[j].Kind {
259				return g.Issues[i].Kind < g.Issues[j].Kind
260			}
261			return g.Issues[i].Message < g.Issues[j].Message
262		})
263		g.Warnings = MessageLines(g.Issues)
264		if g.Warnings == nil {
265			g.Warnings = []string{}
266		}
267	}
