276	func (g *Graph) applyConfig(configs []GraphConfig) {
277		if len(configs) == 0 {
278			return
279		}
280	
281		idToPath := make(map[string]string)
282		cascade := make(map[string][]string)
283		for _, cfg := range configs {
284			for id, rawPath := range cfg.IDToPath {
285				if id == "" || rawPath == "" {
286					continue
287				}
288				idToPath[id] = filepath.Clean(filepath.Join(g.RootDir, rawPath))
289			}
290			for from, tos := range cfg.Cascade {
291				for _, to := range tos {
292					if from == "" || to == "" {
293						continue
294					}
295					cascade[from] = append(cascade[from], to)
296				}
297			}
298			if len(cfg.IDMap) > 0 {
299				for id, rawPath := range cfg.IDMap {
300					if id == "" || rawPath == "" {
301						continue
302					}
303					idToPath[id] = filepath.Clean(filepath.Join(g.RootDir, rawPath))
304				}
305			}
306			if len(cfg.Required) > 0 {
307				for _, id := range cfg.Required {
308					if _, ok := g.Documents[id]; !ok {
309						g.Issues = append(g.Issues, GraphIssue{
310							Kind:    IssueRequiredRootMissing,
311							ID:      id,
312							Message: fmt.Sprintf("required root document %q not found", id),
313						})
314					}
315				}
316			}
317		}
318	
319		if len(idToPath) > 0 {
320			for id, path := range idToPath {
321				if _, ok := g.Documents[id]; ok {
322					continue
323				}
324				if _, err := os.Stat(path); err != nil {
325					g.Issues = append(g.Issues, GraphIssue{
326						Kind:    IssueIDPathMissing,
327						ID:      id,
328						Path:    relPath(g.RootDir, path),
329						Message: fmt.Sprintf("id_to_path entry %q -> %q does not exist", id, path),
330					})
331					continue
332				}
333				doc, err := ParseDocument(path)
334				if err != nil {
335					if errors.Is(err, ErrNotDocGraphDocument) {
336						g.Issues = append(g.Issues, GraphIssue{
337							Kind:    IssueIDPathMissing,
338							ID:      id,
339							Path:    relPath(g.RootDir, path),
340							Message: fmt.Sprintf("id_to_path entry %q -> %q is not a doc graph document", id, path),
341						})
342						continue
343					}
344					g.Issues = append(g.Issues, GraphIssue{
345						Kind:    IssueIDPathMissing,
346						ID:      id,
347						Path:    relPath(g.RootDir, path),
348						Message: fmt.Sprintf("id_to_path entry %q -> %q could not be loaded: %v", id, path, err),
349					})
350					continue
351				}
352				if doc.ID != id {
353					g.Issues = append(g.Issues, GraphIssue{
354						Kind:    IssueIDPathMismatch,
355						ID:      id,
356						Path:    relPath(g.RootDir, path),
357						Message: fmt.Sprintf("id_to_path mismatch for %q: %q declares %q", id, path, doc.ID),
358					})
359					continue
360				}
361				g.Documents[id] = doc
362				doc.Path = relPath(g.RootDir, path)
363				g.PathToID[doc.Path] = id
364			}
365		}
366	
367		for from, toIDs := range cascade {
368			if _, ok := g.Documents[from]; !ok {
369				g.Issues = append(g.Issues, GraphIssue{
370					Kind:    IssueCascadeUnknown,
371					ID:      from,
372					Message: fmt.Sprintf("cascade rule refers to unknown dependency root %q", from),
373				})
374				continue
375			}
376			for _, to := range dedupeSortedStrings(toIDs) {
377				if to == "" {
378					continue
379				}
380				child, ok := g.Documents[to]
381				if !ok {
382					g.Issues = append(g.Issues, GraphIssue{
383						Kind:    IssueCascadeUnknown,
384						ID:      to,
385						Message: fmt.Sprintf("cascade rule refers to unknown target doc %q", to),
386					})
387					continue
388				}
389				if !containsString(child.DependsOn, from) {
390					child.DependsOn = append(child.DependsOn, from)
391				}
392			}
393		}
394	
395		for id := range g.Documents {
396			g.Documents[id].DependsOn = dedupeSortedStrings(g.Documents[id].DependsOn)
397		}
398		g.buildDependents()
399		// Re-run integrity scans that can change after id_to_path/cascade apply.
400		g.rescanAfterConfig()
401		g.detectCycles()
402		g.finalizeWarnings()
403	}
