405	// rescanAfterConfig refreshes integrity detections that depend on the final
406	// document set. Currently this just re-runs missing-dep detection so deps
407	// pulled in by cascade rules or id_to_path entries are evaluated, and dedupes
408	// any duplicate issues introduced by the rescan.
409	func (g *Graph) rescanAfterConfig() {
410		// Wipe prior missing_dep entries because applyConfig may have resolved
411		// some of them by promoting id_to_path targets into Documents.
412		filtered := g.Issues[:0]
413		for _, issue := range g.Issues {
414			if issue.Kind == IssueMissingDep {
415				continue
416			}
417			filtered = append(filtered, issue)
418		}
419		g.Issues = filtered
420		g.detectMissingDeps()
421	}
