423	func findMarkdownFiles(root string, roots []string) ([]string, error) {
424		targetDirs := []string{root}
425		if len(roots) > 0 {
426			targetDirs = roots
427		}
428	
429		files := []string{}
430		for _, base := range targetDirs {
431			cleanRoot := filepath.Clean(base)
432			err := filepath.Walk(cleanRoot, func(path string, info os.FileInfo, err error) error {
433				if err != nil {
434					return nil
435				}
436				if info == nil {
437					return nil
438				}
439				if info.IsDir() {
440					name := filepath.Base(path)
441					// Skip tool-managed directories. .claude is the Claude Code
442					// workspace (including throwaway copies under .claude/worktrees/);
443					// a worktrees/ directory at any depth is agent-scratch and must
444					// not be surfaced as canonical documents.
445					switch name {
446					case ".git", ".ddx", ".claude", "worktrees":
447						return filepath.SkipDir
448					}
449					return nil
450				}
451				if strings.HasPrefix(filepath.Base(path), ".") {
452					return nil
453				}
454				ext := strings.ToLower(filepath.Ext(path))
455				if ext != ".md" {
456					return nil
457				}
458				files = append(files, path)
459				return nil
460			})
461			if err != nil {
462				return nil, err
463			}
464		}
465		sort.Strings(files)
466		return files, nil
467	}
