469	// relPath returns filePath expressed relative to root. If filePath cannot be
470	// made relative (e.g. different volumes on Windows) the cleaned absolute path
471	// is returned. Callers treat the result as the canonical document path.
472	func relPath(root, filePath string) string {
473		clean := filepath.Clean(filePath)
474		if rel, err := filepath.Rel(root, clean); err == nil && !strings.HasPrefix(rel, ".."+string(filepath.Separator)) && rel != ".." {
475			return rel
476		}
477		return clean
478	}
