490	func ParseDocument(path string) (*Document, error) {
491		content, err := os.ReadFile(path)
492		if err != nil {
493			return nil, err
494		}
495	
496		frontmatter, body, err := ParseFrontmatter(content)
497		if err != nil {
498			return nil, err
499		}
500		if !frontmatter.HasFrontmatter || frontmatter.Doc.ID == "" {
501			return nil, fmt.Errorf("%w in %s", ErrNotDocGraphDocument, path)
502		}
503	
504		review := ReviewMetadata{
505			SelfHash:   frontmatter.Doc.Review.SelfHash,
506			ReviewedAt: frontmatter.Doc.Review.ReviewedAt,
507			Deps:       frontmatter.Doc.Review.Deps,
508		}
509		if review.Deps == nil {
510			review.Deps = map[string]string{}
511		}
512	
513		doc := &Document{
514			ID:            frontmatter.Doc.ID,
515			Title:         extractTitle([]byte(body)),
516			DependsOn:     dedupeSortedStrings(frontmatter.Doc.DependsOn),
517			Inputs:        dedupeSortedStrings(frontmatter.Doc.Inputs),
518			Review:        review,
519			ParkingLot:    frontmatter.Doc.ParkingLot,
520			Prompt:        frontmatter.Doc.Prompt,
521			ExecDef:       frontmatter.Doc.Exec,
522			body:          body,
523			bodyLinkTexts: extractBodyLinks(body),
524		}
525		if frontmatter.Raw != nil {
526			doc.frontmatter = frontmatter.Raw
527		}
528	
529		contentHash, err := HashDocument(frontmatter.Raw, body)
530		if err != nil {
531			return nil, err
532		}
533		doc.contentHash = contentHash
534		return doc, nil
535	}
