537	func (g *Graph) buildDependents() {
538		g.Dependents = make(map[string][]string)
539		for id := range g.Documents {
540			g.Dependents[id] = g.Dependents[id][:0]
541		}
542		for id, doc := range g.Documents {
543			for _, dep := range doc.DependsOn {
544				if _, ok := g.Documents[dep]; !ok {
545					continue
546				}
547				if containsString(g.Dependents[dep], id) {
548					continue
549				}
550				g.Dependents[dep] = append(g.Dependents[dep], id)
551			}
552		}
553		for id := range g.Dependents {
554			g.Dependents[id] = dedupeSortedStrings(g.Dependents[id])
555		}
556		for id, doc := range g.Documents {
557			doc.Dependents = append([]string{}, g.Dependents[id]...)
558		}
559	}
