561	func (g *Graph) detectCycles() {
562		index := 0
563		indexes := map[string]int{}
564		lowlinks := map[string]int{}
565		onStack := map[string]bool{}
566		stack := []string{}
567		warned := map[string]struct{}{}
568		var visit func(string)
569	
570		visit = func(id string) {
571			indexes[id] = index
572			lowlinks[id] = index
573			index++
574			stack = append(stack, id)
575			onStack[id] = true
576	
577			node := g.Documents[id]
578			for _, dep := range node.DependsOn {
579				if _, ok := g.Documents[dep]; !ok {
580					continue
581				}
582				if _, ok := indexes[dep]; !ok {
583					visit(dep)
584					if lowlinks[dep] < lowlinks[id] {
585						lowlinks[id] = lowlinks[dep]
586					}
587				} else if onStack[dep] {
588					if indexes[dep] < lowlinks[id] {
589						lowlinks[id] = indexes[dep]
590					}
591				}
592			}
593	
594			if lowlinks[id] == indexes[id] {
595				cycle := []string{}
596				for {
597					last := stack[len(stack)-1]
598					stack = stack[:len(stack)-1]
599					onStack[last] = false
600					cycle = append(cycle, last)
601					if last == id {
602						break
603					}
604				}
605				if len(cycle) > 1 {
606					warnKey := cycleKey(cycle)
607					if _, done := warned[warnKey]; done {
608						return
609					}
610					warned[warnKey] = struct{}{}
611					label := renderCycle(cycle)
612					g.Issues = append(g.Issues, GraphIssue{
613						Kind:    IssueCycle,
614						Message: fmt.Sprintf("cycle detected: %s", label),
615					})
616				} else {
617					parent := g.Documents[id]
618					selfDepends := containsString(parent.DependsOn, id)
619					if selfDepends {
620						label := fmt.Sprintf("%s -> %s", id, id)
621						g.Issues = append(g.Issues, GraphIssue{
622							Kind:    IssueCycle,
623							ID:      id,
624							Message: fmt.Sprintf("cycle detected: %s", label),
625						})
626					}
627				}
628			}
629		}
630	
631		for _, id := range sortedDocIDs(g.Documents) {
632			if _, ok := indexes[id]; !ok {
633				visit(id)
634			}
635		}
636	}
