638	func cycleKey(ids []string) string {
639		if len(ids) == 0 {
640			return ""
641		}
642		copyIDs := append([]string(nil), ids...)
643		sort.Strings(copyIDs)
644		return strings.Join(copyIDs, "::")
645	}
646	
647	func renderCycle(ids []string) string {
648		if len(ids) == 0 {
649			return ""
650		}
651		copyIDs := append([]string(nil), ids...)
652		sort.Strings(copyIDs)
653		start := copyIDs[0]
654		return start + " -> " + strings.Join(copyIDs[1:], " -> ") + " -> " + start
655	}
