657	func (g *Graph) StaleDocs() []StaleReason {
658		if len(g.Documents) == 0 {
659			return nil
660		}
661	
662		direct := map[string][]string{}
663		for id := range g.Documents {
664			doc, ok := g.Documents[id]
665			if !ok || doc.ParkingLot {
666				continue
667			}
668			reasons := staleReasonsForDocument(g, doc)
669			if len(reasons) > 0 {
670				direct[id] = reasons
671			}
672		}
673	
674		final := map[string][]string{}
675		queue := []string{}
676		for id, reasons := range direct {
677			final[id] = append([]string(nil), reasons...)
678			queue = append(queue, id)
679		}
680	
681		seen := map[string]struct{}{}
682		for _, id := range queue {
683			seen[id] = struct{}{}
684		}
685		for i := 0; i < len(queue); i++ {
686			u := queue[i]
687			for _, dep := range g.Dependents[u] {
688				child, ok := g.Documents[dep]
689				if !ok || child.ParkingLot {
690					continue
691				}
692				if _, done := seen[dep]; done {
693					continue
694				}
695				seen[dep] = struct{}{}
696				final[dep] = []string{"upstream stale dependency"}
697				queue = append(queue, dep)
698			}
699		}
700	
701		ids := make([]string, 0, len(final))
702		for id := range final {
703			ids = append(ids, id)
704		}
705		sort.Strings(ids)
706		result := make([]StaleReason, 0, len(ids))
707		for _, id := range ids {
708			doc := g.Documents[id]
709			reason := StaleReason{ID: id, Path: doc.Path, Reasons: final[id]}
710			sort.Strings(reason.Reasons)
711			result = append(result, reason)
712		}
713		return result
714	}
