770	func (g *Graph) ResolvePathsToIDs(targets []string) ([]string, error) {
771		ids := make([]string, 0, len(targets))
772		seen := map[string]struct{}{}
773		for _, target := range targets {
774			if target == "" {
775				continue
776			}
777			if id, ok := g.Documents[target]; ok {
778				if _, done := seen[id.ID]; !done {
779					seen[id.ID] = struct{}{}
780					ids = append(ids, id.ID)
781				}
782				continue
783			}
784			resolved := target
785			if !filepath.IsAbs(resolved) {
786				resolved = filepath.Join(g.RootDir, resolved)
787			}
788			resolved = filepath.Clean(resolved)
789			lookupKey := relPath(g.RootDir, resolved)
790			if id, ok := g.PathToID[lookupKey]; ok {
791				if _, done := seen[id]; !done {
792					seen[id] = struct{}{}
793					ids = append(ids, id)
794				}
795				continue
796			}
797			if info, err := os.Stat(resolved); err == nil && info.IsDir() {
798				err := filepath.Walk(resolved, func(path string, info os.FileInfo, err error) error {
799					if err != nil {
800						return nil
801					}
802					if info.IsDir() {
803						switch info.Name() {
804						case ".git", ".ddx", ".claude", "worktrees":
805							return filepath.SkipDir
806						}
807						return nil
808					}
809					if strings.EqualFold(filepath.Ext(path), ".md") {
810						walkKey := relPath(g.RootDir, path)
811						if id, ok := g.PathToID[walkKey]; ok {
812							if _, done := seen[id]; !done {
813								seen[id] = struct{}{}
814								ids = append(ids, id)
815							}
816						}
817					}
818					return nil
819				})
820				if err != nil {
821					return nil, err
822				}
823				continue
824			}
825			return nil, fmt.Errorf("cannot resolve target %q", target)
826		}
827		if len(ids) == 0 {
828			return nil, fmt.Errorf("no matching targets")
829		}
830		return dedupeSortedStrings(ids), nil
831	}
