833	func (g *Graph) Stamp(targets []string, now time.Time) ([]string, []string, error) {
834		docIDs, err := g.ResolvePathsToIDs(targets)
835		if err != nil {
836			return nil, nil, err
837		}
838	
839		stamped := make([]string, 0, len(docIDs))
840		warnings := []string{}
841		for _, id := range docIDs {
842			doc, ok := g.Documents[id]
843			if !ok {
844				warnings = append(warnings, fmt.Sprintf("document %q not found", id))
845				continue
846			}
847			if doc.frontmatter == nil {
848				warnings = append(warnings, fmt.Sprintf("document %q missing frontmatter", id))
849				continue
850			}
851			review := ReviewMetadata{
852				SelfHash:   doc.contentHash,
853				ReviewedAt: now.UTC().Format(time.RFC3339),
854				Deps:       map[string]string{},
855			}
856			for _, depID := range doc.DependsOn {
857				if dep, ok := g.Documents[depID]; ok {
858					review.Deps[depID] = dep.contentHash
859				}
860			}
861			if review.Deps == nil {
862				review.Deps = map[string]string{}
863			}
864			reviewForWrite := DocReview(review)
865			err := SetReview(doc.frontmatter, reviewForWrite)
866			if err != nil {
867				return stamped, warnings, err
868			}
869			frontmatterText, err := EncodeFrontmatter(doc.frontmatter)
870			if err != nil {
871				return stamped, warnings, err
872			}
873			updated := frontmatterSeparator + "\n" + frontmatterText + "\n" + frontmatterSeparator + "\n" + doc.body
874			if err := os.WriteFile(g.absPath(doc.Path), []byte(updated), 0644); err != nil {
875				return stamped, warnings, err
876			}
877			if doc.Review.ReviewedAt == "" || doc.Review.SelfHash != review.SelfHash {
878				doc.Review = review
879			}
880			stamped = append(stamped, id)
881		}
882		sort.Strings(stamped)
883		return stamped, warnings, nil
884	}
