953	var bodyLinkPattern = regexp.MustCompile(`\[\[([^\[\]]+)\]\]`)
954	
955	// extractBodyLinks returns the raw text inside every [[...]] span in body.
956	// Nested or malformed brackets are skipped.
957	func extractBodyLinks(body string) []string {
958		matches := bodyLinkPattern.FindAllStringSubmatch(body, -1)
959		if len(matches) == 0 {
960			return nil
961		}
962		out := make([]string, 0, len(matches))
963		for _, m := range matches {
964			text := strings.TrimSpace(m[1])
965			if text != "" {
966				out = append(out, text)
967			}
968		}
969		return out
970	}
