972	// slugifyID converts a wikilink label into a lowercase-hyphen slug suitable
973	// for ID matching. Dots are preserved (dotted IDs). Spaces and underscores
974	// become hyphens. Other non-alphanumeric characters are dropped.
975	func slugifyID(text string) string {
976		var b strings.Builder
977		prevHyphen := false
978		for _, r := range strings.ToLower(text) {
979			switch {
980			case unicode.IsLetter(r) || unicode.IsDigit(r) || r == '.':
981				b.WriteRune(r)
982				prevHyphen = false
983			case r == '-' || r == '_' || unicode.IsSpace(r):
984				if !prevHyphen && b.Len() > 0 {
985					b.WriteByte('-')
986					prevHyphen = true
987				}
988			}
989		}
990		result := b.String()
991		return strings.TrimRight(result, "-")
992	}
