994	// resolveBodyLinks merges body [[ID]] references into each document's DependsOn.
995	func (g *Graph) resolveBodyLinks() {
996		for _, doc := range g.Documents {
997			if len(doc.bodyLinkTexts) == 0 {
998				continue
999			}
1000			for _, text := range doc.bodyLinkTexts {
1001				resolved := resolveBodyLinkText(text, g.Documents)
1002				if resolved == "" || resolved == doc.ID {
1003					continue
1004				}
1005				if !containsString(doc.DependsOn, resolved) {
1006					doc.DependsOn = append(doc.DependsOn, resolved)
1007				}
1008			}
1009			doc.DependsOn = dedupeSortedStrings(doc.DependsOn)
1010		}
1011	}
