1013	// resolveBodyLinkText tries to resolve a raw wikilink text to a document ID.
1014	// Resolution order: exact match, then slug match.
1015	func resolveBodyLinkText(text string, docs map[string]*Document) string {
1016		if _, ok := docs[text]; ok {
1017			return text
1018		}
1019		slug := slugifyID(text)
1020		if slug != text {
1021			if _, ok := docs[slug]; ok {
1022				return slug
1023			}
1024		}
1025		return ""
1026	}
