1030		entries, err := os.ReadDir(cfgDir)
1031		if err != nil {
1032			if os.IsNotExist(err) {
1033				return nil, nil
1034			}
1035			return nil, err
1036		}
1037	
1038		configs := []GraphConfig{}
1039		for _, entry := range entries {
1040			if entry.IsDir() {
1041				continue
1042			}
1043			ext := strings.ToLower(filepath.Ext(entry.Name()))
1044			if ext != ".yml" && ext != ".yaml" {
1045				continue
1046			}
1047			cfgPath := filepath.Join(cfgDir, entry.Name())
1048			raw, err := os.ReadFile(cfgPath)
1049			if err != nil {
1050				return nil, fmt.Errorf("read graph config %q: %w", cfgPath, err)
1051			}
1052			var cfg GraphConfig
1053			if err := yaml.Unmarshal(raw, &cfg); err != nil {
1054				return nil, fmt.Errorf("parse graph config %q: %w", cfgPath, err)
1055			}
1056			configs = append(configs, cfg)
1057		}
1058		sort.Slice(configs, func(i, j int) bool {
1059			return len(configs[i].Roots) > len(configs[j].Roots)
1060		})
1061		return configs, nil
